int maximalSquare(char** matrix, int m, int* cs) {
    if (!m) return 0;
    int n = cs[0], best = 0;
    int* dp = calloc(m*n, sizeof(int));
    for (int i=0;i<m;i++) for (int j=0;j<n;j++)
        if (matrix[i][j]=='1') {
            int v = 1;
            if (i && j) {
                int a=dp[(i-1)*n+j], b=dp[i*n+j-1], c=dp[(i-1)*n+j-1];
                v = 1 + (a < b ? (a < c ? a : c) : (b < c ? b : c));
            }
            dp[i*n+j]=v;
            if (v>best) best=v;
        }
    free(dp);
    return best*best;
}
